mapper.select:
SELECT rc.*, sa.area_name, sp.species_name
FROM recapture_record rc
LEFT JOIN sea_area sa ON rc.area_id = sa.id
LEFT JOIN species sp ON rc.species_id = sp.id


        AND rc.area_id = #{areaId}


        AND rc.species_id = #{speciesId}


        AND rc.catch_date >= #{startDate}


        AND rc.catch_date <= #{endDate}


ORDER BY rc.created_at DESC

SELECT rr.species_id, sp.species_name, SUM(rr.actual_quantity) AS release_quantity
FROM release_record rr
LEFT JOIN species sp ON rr.species_id = sp.id


        AND YEAR(rr.release_time) = #{year}


        AND rr.area_id = #{areaId}


        AND rr.species_id = #{speciesId}


GROUP BY rr.species_id, sp.species_name

SELECT rc.species_id, sp.species_name, SUM(rc.catch_weight) AS total_weight, SUM(rc.catch_count) AS total_count
FROM recapture_record rc
LEFT JOIN species sp ON rc.species_id = sp.id


        AND YEAR(rc.catch_date) = #{year}


        AND rc.area_id = #{areaId}


        AND rc.species_id = #{speciesId}


GROUP BY rc.species_id, sp.species_name

SELECT MONTH(catch_date) AS month, SUM(catch_weight) AS total_weight, SUM(catch_count) AS total_count FROM recapture_record
AND YEAR(catch_date) = #{year}
GROUP BY MONTH(catch_date) ORDER BY month
